I have this app to simulate ball physics: 


import 'dart:async';

import 'package:basketball/constants.dart';
import 'package:flutter/material.dart';

class BouncingBallApp extends StatefulWidget {
  const BouncingBallApp({Key? key}) : super(key: key);

  @override
  BouncingBallAppState createState() => BouncingBallAppState();
}

class BouncingBallAppState extends State<BouncingBallApp> {
  double floor = 0.0;
  double ceiling = 0;
  double ballPositionX = 50;
  double ballPositionY = 50;
  double ballVelocityX = 0;
  double ballVelocityY = 0;
  double gravity = 9.8;
  double restitution = 0.8;
  double friction = 0.98;
  bool isDragging = false;
  double rotationAngle = 0.0;

  @override
  void initState() {
    super.initState();
    Timer.periodic(const Duration(milliseconds: 16), (timer) {
      _updateBall(16);
    });
  }

  void _onPanStart(DragStartDetails details) {
    setState(() {
      isDragging = true;
    });
  }

  void _onPanUpdate(DragUpdateDetails details) {
    setState(() {
      ballVelocityX += details.delta.dx;
      ballVelocityY += -details.delta.dy;
    });
  }

  void _onPanEnd(DragEndDetails details) {
    setState(() {
      isDragging = false;
      ballVelocityX *= friction;
      ballVelocityY *= friction;
    });
  }

  void _updateBall(double delta) {
    if (!isDragging) {
      double velocityMagnitude = ballVelocityX.abs().ceil() + ballVelocityY.abs().ceil().toDouble();
      setState(() {
        ballPositionX += ballVelocityX * delta / 100;
        ballPositionY += ballVelocityY * delta / 100;

        if (ballPositionY + AppConstants.ballSize / 2 >= floor) {
// Stop the ball from bouncing if it’s too close to the ground
          ballPositionY = floor - AppConstants.ballSize / 2;
          ballVelocityX *= friction;
          if ((ballVelocityY * ballVelocityY) < 4) {
            ballVelocityY = 0;
          } else {
            ballVelocityY *= -restitution;
          }
        } else if (ballPositionY - AppConstants.ballSize / 2 <= ceiling) {
// Stop the ball from going above the ceiling
          ballPositionY = ceiling + AppConstants.ballSize / 2;
          ballVelocityY *= -restitution;
        } else if ((ballVelocityY * ballVelocityY) + (ballVelocityX * ballVelocityX) < 5) {
// Stop the ball from bouncing if it’s moving too slowly
          ballVelocityY = 0;
          ballVelocityX = 0;
        } else {
          ballVelocityY += gravity * delta / 100;
        }

        if (ballPositionX < AppConstants.ballSize / 2) {
          ballPositionX = AppConstants.ballSize / 2;
          ballVelocityX *= -restitution;
          ballVelocityY *= restitution;
        } else if (ballPositionX > MediaQuery.of(context).size.width - AppConstants.ballSize / 2) {
          ballPositionX = MediaQuery.of(context).size.width - AppConstants.ballSize / 2;
          ballVelocityX *= -restitution;
          ballVelocityY *= restitution;
        }

        rotationAngle += velocityMagnitude * delta / 1000;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    floor = MediaQuery.of(context).size.height;
    return GestureDetector(
      onPanStart: _onPanStart,
      onPanUpdate: _onPanUpdate,
      onPanEnd: _onPanEnd,
      child: Scaffold(
        body: Center(
          child: Stack(
            children: <Widget>[
              Positioned.fill(
                child: Container(
                  color: Colors.grey[300],
                  child: const SizedBox.expand(),
                ),
              ),
              Positioned(
                left: ballPositionX - AppConstants.ballSize / 2,
                top: ballPositionY - AppConstants.ballSize / 2,
                child: const Image(
                  width: AppConstants.ballSize,
                  height: AppConstants.ballSize,
                  image: AssetImage('assets/ball.png'),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

void main() => runApp(MaterialApp(home: BouncingBallApp(key: UniqueKey())));

How to make the ball Image circle accordingly to ball velocity when the ball is moving

One way to achieve this effect is to use the Transform.rotate widget to rotate the ball image based on the velocity magnitude. 

First, add a new variable to store the previous velocity magnitude and initialize it to 0. 

```dart
double previousVelocityMagnitude = 0;
```

Then, inside the _updateBall method, calculate the new velocity magnitude and the difference between it and the previous velocity magnitude. 

```dart
double velocityMagnitude = ballVelocityX.abs().ceil() + ballVelocityY.abs().ceil().toDouble();
double deltaVelocity = velocityMagnitude - previousVelocityMagnitude;
```

Next, update the previousVelocityMagnitude variable to the new velocity magnitude. 

```dart
previousVelocityMagnitude = velocityMagnitude;
```

Finally, add a Transform.rotate widget around the ball image widget and pass in the rotationAngle and deltaVelocity to rotate the ball image when the ball is moving. 

```dart
Transform.rotate(
  angle: rotationAngle + deltaVelocity,
  child: const Image(
    width: AppConstants.ballSize,
    height: AppConstants.ballSize,
    image: AssetImage('assets/ball.png'),
  ),
),
```

